mapper.select:
SELECT vc.call_id, vc.room_id, vc.initiator_id, vc.call_type, vc.status, vc.start_time, vc.end_time, vc.duration, vc.is_auto_created, r.room_name, u.nickname AS initiator_nickname, (SELECT COUNT(*) FROM voice_call_participant WHERE call_id = vc.call_id) AS participant_count, (SELECT COUNT(*) FROM voice_call_participant WHERE call_id = vc.call_id AND connection_status = 1) AS connected_count FROM voice_call vc LEFT JOIN room r ON vc.room_id = r.room_id LEFT JOIN user u ON vc.initiator_id = u.user_id
AND vc.room_id = #{query.roomId}
AND vc.initiator_id = #{query.initiatorId}
AND vc.call_type = #{query.callType}
AND vc.status = #{query.status}
AND vc.start_time >= #{query.startTime}
AND vc.start_time <= #{query.endTime}
AND (r.room_name LIKE CONCAT('%', #{query.keyword}, '%') OR u.nickname LIKE CONCAT('%', #{query.keyword}, '%'))
ORDER BY vc.start_time DESC
